package jetbrains.mps.vcs.diff.ui;

/*Generated by MPS */

import com.intellij.history.integration.ui.views.HistoryDialog;
import jetbrains.mps.project.MPSProject;
import com.intellij.openapi.vcs.history.VcsHistorySession;
import com.intellij.diff.DiffRequestPanel;
import org.jetbrains.mps.openapi.model.SNodeId;
import com.intellij.openapi.vfs.VirtualFile;
import java.util.Collection;
import com.intellij.history.core.LocalHistoryFacade;
import com.intellij.openapi.util.Pair;
import javax.swing.JComponent;
import java.awt.Dimension;
import javax.swing.JPanel;
import com.intellij.ui.ExcludingTraversalPolicy;
import com.intellij.diff.DiffManager;
import javax.swing.border.Border;
import com.intellij.openapi.util.Disposer;

/**
 * Most of this class copied from IDEA's FileHistoryDialog
 */
public final class RootHistoryDialog extends HistoryDialog<RootHistoryModel> {
  private final MPSProject myMPSProject;
  private VcsHistorySession mySession;
  private DiffRequestPanel myDiffPanel;
  private SNodeId myRoot;
  private VirtualFile myActualFile;

  public RootHistoryDialog(MPSProject project) {
    super(project.getProject(), null, null, false);
    myMPSProject = project;
  }


  public void show(VcsHistorySession session, VirtualFile actualFile, Collection<SNodeId> selection) {
    mySession = session;
    // for the moment, I support single node scenario. Moreover, root node, as DiffModelViewer (along with ChangeSet) is incapable to show changes for anything but root 
    myRoot = selection.iterator().next();
    myActualFile = actualFile;
    init();
    show();
  }

  @Override
  protected RootHistoryModel createModel(LocalHistoryFacade facade) {
    return new RootHistoryModel(myMPSProject, mySession, myRoot, myActualFile);
  }

  @Override
  protected Pair<JComponent, Dimension> createDiffPanel(JPanel panel, ExcludingTraversalPolicy policy) {
    myDiffPanel = DiffManager.getInstance().createRequestPanel(myProject, this, getFrame());
    return Pair.<JComponent,Dimension>create(myDiffPanel.getComponent(), null);
  }

  @Override
  protected void setDiffBorder(Border border) {
    // no-op 
  }

  @Override
  public void dispose() {
    super.dispose();
    if (myDiffPanel != null) {
      Disposer.dispose(myDiffPanel);
      myDiffPanel = null;
    }
  }


  @Override
  protected Runnable doUpdateDiffs(final RootHistoryModel model) {
    return new Runnable() {
      @Override
      public void run() {
        myDiffPanel.setRequest(model.createRequest());
      }
    };
  }

  @Override
  protected String getHelpId() {
    // FIXME can I have an MPS-specific one? This value is from FileHistoryDialog 
    return "reference.dialogs.showhistory";
  }
}
